                alt="GSJLF" class="m-logo" />
            <div>
                <div class="m-name">ENT — GSJLF</div>
                <div class="m-sub">Portail Numérique</div>
            </div>
        </div>
        <a href="/personnel/signin" class="m-btn">Se connecter</a>
    </div>
