        </div>
        <div class="pp-tint"></div>
        <div class="pp-grain"></div>
        <div class="pp-top">
            <a href="/personnel/acceuil" class="pp-brand">
                <img
                    src="data:image/png;base64,"
                    alt="GSJLF" class="pp-logo" />
                <div>
                    <div class="pp-brand-n">ENT — GSJLF</div>
                    <div class="pp-brand-s">Portail Numérique</div>
                </div>
            </a>
            <a href="/personnel/acceuil" class="pp-home">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
                    <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" />
                    <polyline points="9 22 9 12 15 12 15 22" />
                </svg>
                Accueil
            </a>
        </div>
        <div class="pp-scroll">
            <div class="ps-line"></div><span class="ps-txt">Défiler</span>
        </div>
        <div class="pp-body">
            <div class="pp-tag" style="animation-delay:.05s">
                <span class="pp-tag-dot" style="background:#D97706;color:#D97706"></span>
                <span class="pp-tag-txt">Nouveau compte</span>
            </div>
            <div class="pp-rule" style="animation-delay:.2s"></div>
            <h2 class="pp-h" style="animation-delay:.15s">Rejoignez la<br /><em>communauté GSJLF</em></h2>
            <p class="pp-p" style="animation-delay:.25s">Créez votre compte en quelques étapes et accédez à tous vos
                services numériques.</p>
            <div class="pp-pills" style="animation-delay:.35s">
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#113B26"></span>UAHB</div>
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#D97706"></span>GSJLF</div>
                <div class="pp-pill"><span class="pp-pill-dot" style="background:#22C55E"></span>CTD</div>
            </div>
        </div>
    </div>
    <div class="form-panel">
        <div class="form-inner">
            <div class="fh">
                <div class="fh-eyebrow">Nouveau compte</div>
                <h1 class="fh-title">Inscription à l'<em>ENT</em></h1>
                <div class="fh-rule"></div>
                <p class="fh-sub">Créez votre espace numérique de travail.</p>
            </div>
            <form novalidate="novalidate" id="formSignUp" autocomplete="off">

                <input type="hidden" name="option" value="1"  />
