                <div class="g2">
                    <div class="ff fv-row">
                        <label>Mot de passe</label>
                        <div class="iw">
                            <svg class="ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"
                                 stroke-linecap="round">
                                <rect x="3" y="11" width="18" height="11" rx="2" />
                                <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                            </svg>
                            <input class="inp suf" type="password" id="pwd1" placeholder="••••••••"
                                   oninput="strength(this.value)" name="password" />
                            <button type="button" class="pw-btn" onclick="togglePwd(this,'pwd1')"><svg viewBox="0 0 24 24"
                                                                                                       fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
                                    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
                                    <circle cx="12" cy="12" r="3" />
                                </svg></button>
                        </div>
                        <div class="sbar" id="sb"><span></span><span></span><span></span><span></span></div>
                        <div class="stxt" id="st"></div>
                    </div>
                    <div class="ff fv-row" >
                        <label>Confirmer</label>
                        <div class="iw">
                            <svg class="ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"
                                 stroke-linecap="round">
                                <rect x="3" y="11" width="18" height="11" rx="2" />
                                <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                            </svg>
                            <input class="inp" type="password" placeholder="••••••••"  name="confirm-password"/>
                        </div>
                    </div>
                </div>
                <div class="terms ">
                    <div class="ff">

                    <input type="checkbox" id="trms"  name="cgu"/>
                    <label for="trms">J'accepte les <a href="#">conditions d'utilisation</a> et la <a href="#">politique de
                            confidentialité</a>.</label>
                    </div>
                    <br>
                </div>
                <button type="submit" class="btn-main fw-bolder" id="formSignUp_submit">

    <span class="indicator-label">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
            <path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
            <circle cx="8.5" cy="7" r="4" />
            <line x1="20" y1="8" x2="20" y2="14" />
            <line x1="23" y1="11" x2="17" y2="11" />
        </svg>
        Créer mon compte
    </span>

                    <span class="indicator-progress">
        Veuillez patienter...
        <span class="spinner-border spinner-border-sm align-middle ms-2"></span>
    </span>

                </button>
                <p class="txt-c" style="margin-top:14px">Déjà un compte ? <a href="/personnel/signin">Se connecter</a></p>
            </form>

            <div class="f-foot">
                <span class="ep"><span class="ep-dot epg"></span>UAHB</span>
                <span class="ep"><span class="ep-dot epb"></span>GSJLF</span>
                <span class="ep"><span class="ep-dot epc"></span>CTD</span>
            </div>
        </div>
    </div>
